import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { CreditCard, CheckCircle, Shield } from 'lucide-react';
import './Checkout.css';

export default function Checkout() {
    const navigate = useNavigate();
    const [bookingData, setBookingData] = useState(null);
    const [isProcessing, setIsProcessing] = useState(false);

    useEffect(() => {
        const data = sessionStorage.getItem('bookingData');
        if (!data) {
            navigate('/');
            return;
        }
        setBookingData(JSON.parse(data));
    }, [navigate]);

    const handlePayment = (e) => {
        e.preventDefault();
        setIsProcessing(true);

        // Mock payment processing simulation
        setTimeout(() => {
            // Add random order ID
            const finalOrder = {
                ...bookingData,
                orderId: 'ORD-' + Math.floor(100000 + Math.random() * 900000)
            };
            sessionStorage.setItem('finalOrder', JSON.stringify(finalOrder));
            navigate('/ticket');
        }, 2000);
    };

    if (!bookingData) return null;

    const tax = Math.round(bookingData.grandTotal * 0.18);
    const totalPayable = bookingData.grandTotal + tax;

    return (
        <div className="checkout-page container animate-fade-in">
            <div className="checkout-grid">
                {/* Order Summary */}
                <div className="order-summary glass-panel">
                    <h2>Order Summary</h2>
                    <div className="movie-summary">
                        <h3>{bookingData.movieTitle}</h3>
                        <p className="text-muted">{bookingData.time} • INOX</p>
                        <p className="seats">Seats: {bookingData.seats.join(', ')}</p>
                    </div>

                    <div className="billing-details">
                        <div className="bill-row">
                            <span>Tickets ({bookingData.seats.length})</span>
                            <span>Rs. {bookingData.seatTotal}</span>
                        </div>

                        {bookingData.beverages?.length > 0 && (
                            <div className="bill-row">
                                <span>Food & Beverages</span>
                                <span>Rs. {bookingData.beverageTotal}</span>
                            </div>
                        )}

                        <div className="bill-row">
                            <span>Convenience Fee & Taxes (18%)</span>
                            <span>Rs. {tax}</span>
                        </div>

                        <div className="bill-row total-row">
                            <span>Amount Payable</span>
                            <span>Rs. {totalPayable}</span>
                        </div>
                    </div>
                </div>

                {/* Payment Section */}
                <div className="payment-section glass-panel">
                    <div className="payment-header">
                        <h2>Payment Details</h2>
                        <div className="secure-badge">
                            <Shield size={16} /> 100% Secure
                        </div>
                    </div>

                    <form className="payment-form" onSubmit={handlePayment}>
                        <div className="form-group">
                            <label>Name on Card</label>
                            <input type="text" placeholder="John Doe" required />
                        </div>

                        <div className="form-group">
                            <label>Card Number</label>
                            <div className="input-with-icon">
                                <CreditCard size={20} className="icon" />
                                <input type="text" placeholder="XXXX XXXX XXXX XXXX" maxLength="19" required />
                            </div>
                        </div>

                        <div className="form-row">
                            <div className="form-group">
                                <label>Expiry Date</label>
                                <input type="text" placeholder="MM/YY" maxLength="5" required />
                            </div>
                            <div className="form-group">
                                <label>CVV</label>
                                <input type="password" placeholder="XXX" maxLength="3" required />
                            </div>
                        </div>

                        <button
                            type="submit"
                            className={`btn-primary w-100 pay-btn ${isProcessing ? 'processing' : ''}`}
                            disabled={isProcessing}
                        >
                            {isProcessing ? 'Processing Payment...' : `Pay Rs. ${totalPayable}`}
                        </button>
                    </form>
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Mic, Search, Play, Star, Sparkles } from 'lucide-react';
import { movies } from '../data/mockData';
import './Home.css';

export default function Home() {
    const [isListening, setIsListening] = useState(false);
    const [searchQuery, setSearchQuery] = useState('');
    const navigate = useNavigate();

    // Voice Search Mock (or actual if browser supports)
    const handleVoiceSearch = () => {
        setIsListening(true);
        // Setup SpeechRecognition
        if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
            const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
            const recognition = new SpeechRecognition();
            recognition.onresult = (event) => {
                const transcript = event.results[0][0].transcript;
                setSearchQuery(transcript);
                setIsListening(false);
            };
            recognition.onerror = () => setIsListening(false);
            recognition.onend = () => setIsListening(false);
            recognition.start();
        } else {
            setTimeout(() => {
                setSearchQuery("Dune");
                setIsListening(false);
            }, 2000);
        }
    };

    const filteredMovies = movies.filter(m => m.title.toLowerCase().includes(searchQuery.toLowerCase()));

    // AI Ordered logic
    const aiRecommended = [...movies].sort((a, b) => b.aiMatch - a.aiMatch).slice(0, 3);

    return (
        <div className="home-page animate-fade-in">
            {/* Hero Section */}
            <section className="hero">
                <div className="hero-bg" style={{ backgroundImage: `url(${movies[0].image})` }} />
                <div className="hero-overlay" />
                <div className="container hero-content">
                    <div className="ai-badge hero-badge"><Sparkles size={14} /> AI Top Pick</div>
                    <h1 className="hero-title">{movies[0].title}</h1>
                    <p className="hero-meta">{movies[0].genre} • {movies[0].duration}</p>
                    <p className="hero-synopsis">{movies[0].synopsis}</p>
                    <div className="hero-actions">
                        <Link to={`/movie/${movies[0].id}`} className="btn-primary hero-btn">
                            <Ticket size={20} /> Book Tickets
                        </Link>
                        <button className="btn-secondary hero-btn">
                            <Play size={20} /> Watch Trailer
                        </button>
                    </div>
                </div>
            </section>

            {/* Voice Search Bar */}
            <section className="search-section container">
                <div className="search-bar glass-panel">
                    <Search className="search-icon" size={24} />
                    <input
                        type="text"
                        placeholder="Search for movies, genres, or actors..."
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                    />
                    <button
                        className={`mic-btn ${isListening ? 'listening' : ''}`}
                        onClick={handleVoiceSearch}
                        title={isListening ? "Listening..." : "Search by Voice"}
                    >
                        <Mic size={24} />
                    </button>
                </div>
            </section>

            {/* Recommended Movies (AI) */}
            <section className="movies-section container">
                <div className="section-header">
                    <h2><Sparkles className="ai-icon" size={28} /> AI Recommended For You</h2>
                    <p className="subtitle">Based on your viewing history and preferences</p>
                </div>
                <div className="movie-grid">
                    {aiRecommended.map(movie => (
                        <div key={`ai-${movie.id}`} className="movie-card" onClick={() => navigate(`/movie/${movie.id}`)}>
                            <div className="movie-poster">
                                <img src={movie.image} alt={movie.title} loading="lazy" />
                                <div className="ai-match-badge">{movie.aiMatch}% Match</div>
                            </div>
                            <div className="movie-info">
                                <h3>{movie.title}</h3>
                                <div className="movie-stats">
                                    <span>{movie.genre}</span>
                                    <span className="rating"><Star size={14} fill="currentColor" /> {movie.rating}</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
            </section>

            {/* All Now Showing */}
            <section className="movies-section container" style={{ marginTop: '60px' }}>
                <div className="section-header">
                    <h2>Now Showing</h2>
                </div>
                <div className="movie-grid">
                    {filteredMovies.map(movie => (
                        <div key={movie.id} className="movie-card" onClick={() => navigate(`/movie/${movie.id}`)}>
                            <div className="movie-poster">
                                <img src={movie.image} alt={movie.title} loading="lazy" />
                            </div>
                            <div className="movie-info">
                                <h3>{movie.title}</h3>
                                <div className="movie-stats">
                                    <span>{movie.genre}</span>
                                    <span className="rating"><Star size={14} fill="currentColor" /> {movie.rating}</span>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
                {filteredMovies.length === 0 && (
                    <div className="no-results">No movies found mapping your search.</div>
                )}
            </section>
        </div>
    );
}

